From f5ae728081353ae872ad85355f1a5fcafd761e22 Mon Sep 17 00:00:00 2001
From: Camille Letavernier <cletavernier@eclipsesource.com>
Date: Fri, 28 Feb 2025 15:16:41 +0100
Subject: [PATCH] 15048: delete the change set when all changes are deleted

fixes #15048
---
 packages/ai-chat/src/common/chat-service.ts | 4 ++++
 1 file changed, 4 insertions(+)

diff --git a/packages/ai-chat/src/common/chat-service.ts b/packages/ai-chat/src/common/chat-service.ts
index 83d0db1df10a2..fd5fa912850b6 100644
--- a/packages/ai-chat/src/common/chat-service.ts
+++ b/packages/ai-chat/src/common/chat-service.ts
@@ -317,5 +317,9 @@ export class ChatServiceImpl implements ChatService {

     deleteChangeSetElement(sessionId: string, index: number): void {
         this.getSession(sessionId)?.model.changeSet?.removeElements(index);
+        const elements = this.getSession(sessionId)?.model.changeSet?.getElements();
+        if (elements?.length === 0) {
+            this.deleteChangeSet(sessionId);
+        }
     }
 }
